}
```

### Duration Handler

Magic-named mechanic. Same permission model as any mechanic (can read entity state, roll dice, no side effects beyond return value).

```ttrpg
mechanic duration_handler(duration: Duration, dt: int, bearer: entity, timer: Timer) -> option<Timer> {
    let new_elapsed = timer.elapsed + dt
    match duration {
        Rounds(n) => {
            if new_elapsed >= n { none }
            else { some(Timer { elapsed: new_elapsed }) }
        }
        SaveEvery(interval, cat, mental) => {
            if new_elapsed >= interval {
                if resist_spell_check(bearer, some(cat), mental) {
